#include <rime/candidate.h>
#include <rime/segmentation.h>
#include "trivial_translator.h"

namespace sample {

TrivialTranslator::TrivialTranslator(const Ticket& ticket)
    : Translator(ticket) {
  dictionary_["yi"] = "\xe4\xb8\x80";    // 一
  dictionary_["er"] = "\xe4\xba\x8c";    // 二
  dictionary_["san"] = "\xe4\xb8\x89";   // 三
  dictionary_["si"] = "\xe5\x9b\x9b";    // 四
  dictionary_["wu"] = "\xe4\xba\x94";    // 五
  dictionary_["liu"] = "\xe5\x85\xad";   // 六
  dictionary_["qi"] = "\xe4\xb8\x83";    // 七
  dictionary_["ba"] = "\xe5\x85\xab";    // 八
  dictionary_["jiu"] = "\xe4\xb9\x9d";   // 九
  dictionary_["ling"] = "\xe3\x80\x87";  // 〇
  dictionary_["shi"] = "\xe5\x8d\x81";   // 十
  dictionary_["bai"] = "\xe7\x99\xbe";   // 百
  dictionary_["qian"] = "\xe5\x8d\x83";  // 千
  dictionary_["wan"] = "\xe8\x90\xac";   // 萬
}

an<Translation> TrivialTranslator::Query(const string& input,
                                         const Segment& segment) {
  if (!segment.HasTag("abc"))
    return nullptr;
  DLOG(INFO) << "input = '" << input << "', [" << segment.start << ", "
             << segment.end << ")";
  string output = Translate(input);
  if (output.empty()) {
    return nullptr;
  }
  auto candidate = New<SimpleCandidate>("trivial", segment.start, segment.end,
                                        output, ":-)");
  return New<UniqueTranslation>(candidate);
}

string TrivialTranslator::Translate(const string& input) {
  const size_t kMinPinyinLength = 2;
  const size_t kMaxPinyinLength = 6;
  string result;
  size_t input_len = input.length();
  for (size_t i = 0; i < input_len;) {
    int translated = 0;
    size_t len = (std::max)(kMaxPinyinLength, input_len - i);
    for (; len >= kMinPinyinLength; --len) {
      auto it = dictionary_.find(input.substr(i, len));
      if (it != dictionary_.end()) {
        result += it->second;
        translated = len;
        break;
      }
    }
    if (translated) {
      i += translated;
    } else {
      return string();
    }
  }
  return result;
}

}  // namespace sample

#!/bin/bash

if [[ -z "${1}" ]]; then
  echo "Usage: $(basename "$0") <plugin-name>"
  exit 1
fi

plugin_name="${1/_/-}"
plugin_name="${plugin_name#rime-}"
plugin_dir="plugins/${plugin_name}"
plugin_module="${plugin_name/-/_}"

echo "plugin_name: rime-${plugin_name}"
echo "plugin_dir: ${plugin_dir}"
echo "plugin_module: ${plugin_module}"

mkdir -p "${plugin_dir}"

cat >> "${plugin_dir}/CMakeLists.txt" << //EOF
project(rime-${plugin_name})
cmake_minimum_required(VERSION 3.10)

aux_source_directory(src ${plugin_module}_src)

add_library(rime-${plugin_name}-objs OBJECT \${${plugin_module}_src})
if(BUILD_SHARED_LIBS)
  set_target_properties(rime-${plugin_name}-objs
    PROPERTIES
    POSITION_INDEPENDENT_CODE ON)
endif()

set(plugin_name rime-${plugin_name} PARENT_SCOPE)
set(plugin_objs \$<TARGET_OBJECTS:rime-${plugin_name}-objs> PARENT_SCOPE)
set(plugin_deps \${rime_library} PARENT_SCOPE)
set(plugin_modules "${plugin_module}" PARENT_SCOPE)
//EOF

mkdir -p "${plugin_dir}/src"

cat >> "${plugin_dir}/src/${plugin_module}_module.cc" << //EOF
#include <rime/component.h>
#include <rime/registry.h>
#include <rime_api.h>

#include "todo_processor.h"

using namespace rime;

static void rime_${plugin_module}_initialize() {
  Registry &r = Registry::instance();
  r.Register("todo_processor", new Component<TodoProcessor>);
}

static void rime_${plugin_module}_finalize() {
}

RIME_REGISTER_MODULE(${plugin_module})
//EOF

cat >> "${plugin_dir}/src/todo_processor.h" << //EOF
#include <rime/common.h>
#include <rime/context.h>
#include <rime/engine.h>
#include <rime/processor.h>

using namespace rime;

class TodoProcessor : public Processor {
 public:
  explicit TodoProcessor(const Ticket& ticket)
    : Processor(ticket) {
    Context* context = engine_->context();
    update_connection_ = context->update_notifier()
      .connect([this](Context* ctx) { OnUpdate(ctx); });
  }

  virtual ~TodoProcessor() {
    update_connection_.disconnect();
  }

  ProcessResult ProcessKeyEvent(const KeyEvent& key_event) override {
    return kNoop;
  }

 private:
  void OnUpdate(Context* ctx) {}

  connection update_connection_;
};
//EOF

